<span class="line">                    <span class="token keyword">const</span> name <span class="token operator">=</span> req<span class="token punctuation">.</span>user<span class="token operator">?.</span>id <span class="token operator">||</span> <span class="token string">&#39;anonymous&#39;</span><span class="token punctuation">;</span></span>
